#!/usr/bin/env bash
set -Eeuo pipefail

DEFAULT_REPO_ROOT="/mnt/c/Users/nejat/OneDrive/Desktop/UN/Skills/GitHub 2026/budgetmem-r"
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
MODE="${1:-full}"

case "$MODE" in
    full|smoke|resume|install-only) ;;
    *)
        printf 'ERROR: Unsupported mode: %s\n' "$MODE" >&2
        printf 'Use: full, smoke, resume, or install-only.\n' >&2
        exit 2
        ;;
esac

if [[ -d "$SCRIPT_DIR/.git" ]]; then
    REPO_ROOT="$SCRIPT_DIR"
else
    REPO_ROOT="${BUDGETMEM_REPO_ROOT:-$DEFAULT_REPO_ROOT}"
fi

if [[ ! -d "$REPO_ROOT/.git" ]]; then
    printf 'ERROR: budgetmem-r Git repository not found: %s\n' "$REPO_ROOT" >&2
    exit 1
fi

cd "$REPO_ROOT"
PYTHON="$REPO_ROOT/.venv/bin/python"
if [[ ! -x "$PYTHON" ]]; then
    printf 'ERROR: WSL virtual-environment Python not found: %s\n' "$PYTHON" >&2
    exit 1
fi

required_files=(
    "src/budgetmem/models/budgetmem_r.py"
    "src/budgetmem/memory/budget_state.py"
    "scripts/data/generate_synthetic.py"
    "configs/data/synthetic.yaml"
    "reports/evidence/pretraining_gate_report.json"
)
for relative_path in "${required_files[@]}"; do
    if [[ ! -f "$relative_path" ]]; then
        printf 'ERROR: Section 15 prerequisite is missing: %s\n' "$relative_path" >&2
        exit 1
    fi
done

export PYTHONPATH="$REPO_ROOT/src"
export PYTHONHASHSEED="2026"
export CUDA_VISIBLE_DEVICES=""
export OMP_NUM_THREADS="1"
export MKL_NUM_THREADS="1"
export OPENBLAS_NUM_THREADS="1"
export NUMEXPR_NUM_THREADS="1"
export TOKENIZERS_PARALLELISM="false"

"$PYTHON" - <<'PREGATEPY'
import json
from pathlib import Path

path = Path("reports/evidence/pretraining_gate_report.json")
report = json.loads(path.read_text(encoding="utf-8"))
status = report.get("status") or report.get("overall_status") or report.get("gate_status")
if str(status).upper() != "PASS":
    raise SystemExit(
        f"Section 14 pretraining gate is {status!r}, not 'PASS'. "
        "Do not begin the pilot."
    )
print("Section 14 pretraining gate: PASS")
PREGATEPY

timestamp="$(date +%Y%m%d_%H%M%S)"
backup_root="$REPO_ROOT/.section15_backup/$timestamp"
backup_created=0

write_generated_file() {
    local relative_path="$1"
    local encoded_content="$2"
    local destination="$REPO_ROOT/$relative_path"
    mkdir -p "$(dirname "$destination")"
    if [[ -f "$destination" ]]; then
        local backup_destination="$backup_root/$relative_path"
        mkdir -p "$(dirname "$backup_destination")"
        cp -f "$destination" "$backup_destination"
        backup_created=1
    fi
    printf '%s' "$encoded_content" | base64 --decode > "$destination"
    printf 'WROTE  %s\n' "$relative_path"
}

printf '\n============================================================\n'
printf 'SECTION 15 - PILOT EXPERIMENT\n'
printf 'CPU-ONLY WSL / VS CODE BASH AUTOMATION\n'
printf 'MODE: %s\n' "$MODE"
printf '============================================================\n'

declare -A FILES=(
    ["configs/experiments/pilot.yaml"]=""
    ["src/budgetmem/experiments/__init__.py"]="IiIiRXhwZXJpbWVudCBvcmNoZXN0cmF0aW9uIHV0aWxpdGllcy4iIiIKCmZyb20gYnVkZ2V0bWVtLmV4cGVyaW1lbnRzLnBpbG90IGltcG9ydCBydW5fcGlsb3QsIHN1bW1hcml6ZV9nb19ub19nbwoKX19hbGxfXyA9IFsicnVuX3BpbG90IiwgInN1bW1hcml6ZV9nb19ub19nbyJdCg=="
    ["src/budgetmem/experiments/pilot.py"]=""
    ["scripts/run_pilot.py"]=""
    ["tests/pilot/__init__.py"]="IiIiU2VjdGlvbiAxNSBwaWxvdCB0ZXN0cy4iIiIK"
    ["tests/pilot/test_pilot.py"]=""
    ["docs/pilot_protocol.md"]=""
)

for relative_path in "${!FILES[@]}"; do
    write_generated_file "$relative_path" "${FILES[$relative_path]}"
done

mkdir -p outputs reports/tables reports/evidence

gitignore_marker="# Section 15 pilot operational artifacts"
touch .gitignore
if ! grep -Fq "$gitignore_marker" .gitignore; then
    cat >> .gitignore <<'GITIGNORE'

# Section 15 pilot operational artifacts
outputs/pilot/
.section15_backup/
GITIGNORE
    printf 'UPDATED .gitignore\n'
fi

printf '\nCompiling Section 15 Python files.\n'
"$PYTHON" -m compileall -q \
    "src/budgetmem/experiments" \
    "scripts/run_pilot.py" \
    "tests/pilot"

if "$PYTHON" -c "import importlib.util; raise SystemExit(0 if importlib.util.find_spec('ruff') else 1)"
then
    printf 'Formatting and checking Section 15 files with Ruff.\n'
    ruff_targets=(
        "src/budgetmem/experiments"
        "scripts/run_pilot.py"
        "tests/pilot"
    )
    "$PYTHON" -m ruff format "${ruff_targets[@]}"
    "$PYTHON" -m ruff check "${ruff_targets[@]}"
else
    printf 'WARNING: Ruff is not installed; formatting checks were skipped.\n' >&2
fi

printf '\nRunning focused Section 15 tests.\n'
"$PYTHON" -m pytest tests/pilot/test_pilot.py -q

if [[ "$MODE" == "install-only" ]]; then
    printf '\nSECTION 15 FILES INSTALLED; PILOT WAS NOT RUN.\n'
else
    printf '\nRunning the Section 15 pilot.\n'
    pilot_args=(
        "scripts/run_pilot.py"
        "--config"
        "configs/experiments/pilot.yaml"
    )
    if [[ "$MODE" == "smoke" ]]; then
        pilot_args+=("--smoke")
    elif [[ "$MODE" == "resume" ]]; then
        pilot_args+=("--resume")
    fi
    "$PYTHON" "${pilot_args[@]}"

    printf '\nPilot decision artifact:\n'
    "$PYTHON" - <<'DECISIONPY'
import json
from pathlib import Path

path = Path("reports/evidence/pilot_go_no_go.json")
payload = json.loads(path.read_text(encoding="utf-8"))
print(f"STATUS: {payload['status']}")
print(payload["decision"])
for name, passed in payload["criteria"].items():
    print(f"  {'PASS' if passed else 'FAIL'}  {name}")
DECISIONPY
fi

printf '\nChecking Git whitespace and repository status.\n'
git diff --check
git status --short

printf '\n============================================================\n'
printf 'SECTION 15 AUTOMATION COMPLETED\n'
printf '============================================================\n'
printf '%s\n' \
    'Created:' \
    '  - configs/experiments/pilot.yaml' \
    '  - configuration-driven CPU pilot runner' \
    '  - GRU, uniform-cache, reservoir-cache, and BudgetMem-R comparison' \
    '  - strict budget, write-behavior, retention, resource, and resume checks' \
    '  - reports/tables/pilot_results.csv' \
    '  - reports/evidence/pilot_summary.json' \
    '  - reports/evidence/pilot_go_no_go.json' \
    '  - reports/pilot_report.md'

if [[ "$backup_created" -eq 1 ]]; then
    printf 'Backup directory: %s\n' "$backup_root"
fi

printf '\nInterpretation rule:\n'
printf '  GO    = the full experiment matrix may begin.\n'
printf '  NO_GO = repair failed pilot criteria and rerun Section 15.\n'
printf '  SMOKE_ONLY = infrastructure test only; not a research decision.\n'
